-- Create satellite tables for ship data
-- These tables reference the ships table by UUID

CREATE TABLE IF NOT EXISTS ship_flight_stats (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    ship_id UUID UNIQUE NOT NULL REFERENCES ships(id) ON DELETE CASCADE,
    scm_speed FLOAT,
    max_speed FLOAT,
    boost_speed_forward FLOAT,
    boost_speed_backward FLOAT,
    pitch FLOAT,
    yaw FLOAT,
    roll FLOAT,
    pitch_boosted FLOAT,
    yaw_boosted FLOAT,
    roll_boosted FLOAT,
    accel_forward FLOAT,
    accel_backward FLOAT,
    accel_up FLOAT,
    accel_down FLOAT,
    accel_strafe FLOAT,
    accel_forward_g FLOAT,
    accel_backward_g FLOAT,
    accel_up_g FLOAT,
    accel_down_g FLOAT,
    accel_strafe_g FLOAT,
    boost_mult_forward FLOAT,
    boost_mult_backward FLOAT,
    boost_mult_up FLOAT,
    boost_mult_strafe FLOAT,
    boost_capacitor_max FLOAT,
    boost_regen_per_sec FLOAT,
    boost_regen_time FLOAT,
    zero_to_scm FLOAT,
    zero_to_max FLOAT,
    scm_to_zero FLOAT,
    mass_empty FLOAT,
    mass_loadout FLOAT,
    mass_total FLOAT
);

CREATE TABLE IF NOT EXISTS ship_resistances (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    ship_id UUID UNIQUE NOT NULL REFERENCES ships(id) ON DELETE CASCADE,
    armor_hp FLOAT,
    dmg_mult_physical FLOAT,
    dmg_mult_energy FLOAT,
    dmg_mult_distortion FLOAT,
    dmg_mult_thermal FLOAT,
    dmg_mult_biochemical FLOAT,
    dmg_mult_stun FLOAT,
    sig_mult_cross_section FLOAT,
    sig_mult_infrared FLOAT,
    sig_mult_electromagnetic FLOAT,
    pen_resist_base FLOAT,
    pen_resist_physical FLOAT,
    pen_resist_energy FLOAT,
    pen_resist_distortion FLOAT,
    base_em_signature FLOAT,
    base_ir_signature FLOAT,
    base_cs_signature FLOAT,
    cross_section_x FLOAT,
    cross_section_y FLOAT,
    cross_section_z FLOAT,
    em_total_shields FLOAT,
    em_total_quantum FLOAT,
    ir_total_shields FLOAT,
    ir_total_quantum FLOAT
);

CREATE TABLE IF NOT EXISTS ship_fuel (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    ship_id UUID UNIQUE NOT NULL REFERENCES ships(id) ON DELETE CASCADE,
    hydrogen_capacity FLOAT,
    fuel_intake_rate FLOAT,
    fuel_usage_main FLOAT,
    fuel_usage_retro FLOAT,
    fuel_usage_maneuvering FLOAT,
    maneuvering_time_till_empty FLOAT,
    intake_to_main_ratio FLOAT,
    quantum_capacity FLOAT,
    quantum_range FLOAT,
    quantum_speed FLOAT,
    quantum_spool_time FLOAT,
    quantum_travel_time_po FLOAT,
    quantum_fuel_usage_po FLOAT,
    thrust_main FLOAT,
    thrust_retro FLOAT,
    thrust_maneuvering FLOAT,
    power_generation FLOAT,
    power_used_shields FLOAT,
    power_used_quantum FLOAT,
    cooling_generation FLOAT,
    cooling_used_shields FLOAT,
    cooling_used_quantum FLOAT,
    shield_hp_total FLOAT,
    shield_regen_total FLOAT
);

CREATE TABLE IF NOT EXISTS ship_insurance (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    ship_id UUID UNIQUE NOT NULL REFERENCES ships(id) ON DELETE CASCADE,
    expedited_cost FLOAT,
    expedited_claim_time FLOAT,
    standard_claim_time FLOAT
);


BEGIN;


COMMIT;